import { Shield, Brain, Globe, Network, Gamepad2, Database } from 'lucide-react';
import SectionHeader from './SectionHeader';
import GlassCard from './GlassCard';
import { useApp } from '../context/AppContext';
import t from '../i18n/translations';
import { ink, muted } from '../utils/glass';

export default function About() {
  const { dark, lang } = useApp();
  const tr = t[lang];
  const bg = dark ? '#13131e' : '#f5f0e8';

  const skills = [
    { Icon: Shield,   key: 'cyber',  glow: 'rgba(42,157,143,0.25)' },
    { Icon: Brain,    key: 'ai',     glow: 'rgba(240,165,0,0.25)'  },
    { Icon: Network,  key: 'net',    glow: 'rgba(77,143,255,0.25)' },
    { Icon: Globe,    key: 'web',    glow: 'rgba(42,157,143,0.22)' },
    { Icon: Gamepad2, key: 'game',   glow: 'rgba(240,165,0,0.22)'  },
    { Icon: Database, key: 'db',     glow: 'rgba(168,85,247,0.22)' },
  ];

  return (
    <section id="about" style={{ background: bg }} className="py-24 px-[5%] transition-colors duration-300">
      <SectionHeader tag={tr.aboutTag} title={tr.aboutTitle} />
      <div className="grid md:grid-cols-2 gap-16 items-start">

        {/* Text */}
        <div className="space-y-5">
          {[tr.aboutP1, tr.aboutP2].map((p, i) => (
            <p key={i} className="reveal text-[1rem] leading-[1.9]"
              style={{ color: muted(dark), transitionDelay: `${i * 0.1}s` }}>
              {p}
            </p>
          ))}
          <div className="reveal space-y-2 pt-1" style={{ transitionDelay: '0.2s' }}>
            {[
              { e:'🏅', t: lang==='ar' ? 'بطل الكشافة الوطني — المركز الأول (2020)' : 'National Scout Excellence Champion — 1st Place (2020)' },
              { e:'🏆', t: lang==='ar' ? 'مديرية أسيوط — المركز الأول (2019)'       : '2019 · Asyut Directorate — Scout Excellence, 1st Place' },
            ].map((b, i) => (
              <div key={i} className="inline-flex items-center gap-2 px-4 py-2 rounded-full text-xs font-semibold"
                style={{ display:'flex', background:'rgba(240,165,0,0.09)', border:'1px solid rgba(240,165,0,0.25)', color:'#e8920a', marginBottom:6 }}>
                {b.e} {b.t}
              </div>
            ))}
          </div>
        </div>

        {/* Skills grid */}
        <div className="grid grid-cols-2 gap-3">
          {skills.map(({ Icon, key, glow }, i) => (
            <GlassCard key={key} dark={dark} glow={glow}
              className="reveal rounded-xl"
              style={{ transitionDelay: `${i * 0.07}s` }}>
              <div className="flex items-center gap-3 px-4 py-3.5">
                <span style={{ color:'#f0a500', flexShrink:0 }}><Icon size={18}/></span>
                <span className="text-sm font-medium" style={{ color:ink(dark) }}>{tr.skills[key]}</span>
              </div>
            </GlassCard>
          ))}
        </div>
      </div>
    </section>
  );
}
